- 'connoisseurs' refers to customers who have a preference for 'taste' with a value of 4 or higher, indicating a high standard for taste;
- 'refined palate' refers to the preference for 'taste' with a value of 4 or higher;
- 'big spenders' refers to customers with an average total spend greater than $10.00.

sql:
SELECT store_name
FROM stores
ORDER BY store_name;

SELECT AVG(total_spend) AS average_lifetime_spend
FROM (
  SELECT cust_id, SUM(total_spend) AS total_spend
  FROM transactions
  GROUP BY cust_id
) AS customer_spend;
